module multi_pipe_8bit
(
    input clk,
    input rst_n,
    input mul_en_in,
    input mul_a,
    input mul_b,
    output mul_en_out,
    output mul_out
);

reg [7:0] mul_a_reg, mul_b_reg;
reg [15:0] partial_products [7:0];
reg [15:0] sum [7:0];
reg [2:0] stage;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_a_reg <= 8'b0;
        mul_b_reg <= 8'b0;
        stage <= 3'b0;
    end
    else begin
        if (mul_en_in) begin
            mul_a_reg <= mul_a;
            mul_b_reg <= mul_b;
            stage <= 3'b0;
        end
        else begin
            stage <= stage + 1;
        end
    end
end

wire [15:0] temp [7:0];
genvar i;
generate
    for (i = 0; i < 8; i = i + 1) begin
        assign temp[i] = mul_a_reg[i] ? {8'b0, mul_b_reg} << i : 16'b0;
    end
endgenerate

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        for (int i = 0; i < 8; i = i + 1) begin
            partial_products[i] <= 16'b0;
        end
    end
    else begin
        if (stage == 3'b0) begin
            for (int i = 0; i < 8; i = i + 1) begin
                partial_products[i] <= temp[i];
            end
        end
        else begin
            for (int i = 0; i < 8; i = i + 1) begin
                if (i == 0) begin
                    sum[i] <= partial_products[i];
                end
                else begin
                    sum[i] <= sum[i-1] + partial_products[i];
                end
            end
        end
    end
end

assign mul_en_out = stage == 3'b111;
assign mul_out = sum[7];

endmodule
